    public Object parseFundingRate(Object contract, Object... optionalArgs)
    {
        //
        //     {
        //         "close": 30600.5,
        //         "contract_type": "perpetual_futures",
        //         "funding_rate": "0.00602961",
        //         "greeks": null,
        //         "high": 30803.0,
        //         "low": 30265.5,
        //         "mark_basis": "-0.45601594",
        //         "mark_price": "30600.10481568",
        //         "oi": "469.9190",
        //         "oi_change_usd_6h": "2226314.9900",
        //         "oi_contracts": "469919",
        //         "oi_value": "469.9190",
        //         "oi_value_symbol": "BTC",
        //         "oi_value_usd": "14385640.6802",
        //         "open": 30458.5,
        //         "price_band": {
        //             "lower_limit": "29067.08312627",
        //             "upper_limit": "32126.77608693"
        //         },
        //         "product_id": 139,
        //         "quotes": {
        //             "ask_iv": null,
        //             "ask_size": "965",
        //             "best_ask": "30600.5",
        //             "best_bid": "30599.5",
        //             "bid_iv": null,
        //             "bid_size": "196",
        //             "impact_mid_price": null,
        //             "mark_iv": "-0.44931641"
        //         },
        //         "size": 1226303,
        //         "spot_price": "30612.85362773",
        //         "symbol": "BTCUSDT",
        //         "timestamp": 1689136597460456,
        //         "turnover": 37392218.45999999,
        //         "turnover_symbol": "USDT",
        //         "turnover_usd": 37392218.45999999,
        //         "volume": 1226.3029999999485
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeIntegerProduct(contract, "timestamp", 0.001);
        Object marketId = this.safeString(contract, "symbol");
        Object fundingRateString = this.safeString(contract, "funding_rate");
        Object fundingRate = Precise.stringDiv(fundingRateString, "100");
        return new java.util.HashMap<String, Object>() {{
            put( "info", contract );
            put( "symbol", DeltaCore.this.safeSymbol(marketId, market) );
            put( "markPrice", DeltaCore.this.safeNumber(contract, "mark_price") );
            put( "indexPrice", DeltaCore.this.safeNumber(contract, "spot_price") );
            put( "interestRate", null );
            put( "estimatedSettlePrice", null );
            put( "timestamp", timestamp );
            put( "datetime", DeltaCore.this.iso8601(timestamp) );
            put( "fundingRate", DeltaCore.this.parseNumber(fundingRate) );
            put( "fundingTimestamp", null );
            put( "fundingDatetime", null );
            put( "nextFundingRate", null );
            put( "nextFundingTimestamp", null );
            put( "nextFundingDatetime", null );
            put( "previousFundingRate", null );
            put( "previousFundingTimestamp", null );
            put( "previousFundingDatetime", null );
            put( "interval", null );
        }};
    }

