            //                 "insurance_fund_margin_contribution": "1",
            //                 "price_band": "2",
            //                 "annualized_funding": "10.95",
            //                 "impact_size": 200,
            //                 "contract_type": "call_options",
            //                 "position_size_limit": 255633,
